const chapterPlan = $('Select Next Chapter Plan').first().json;
const project = $('Load Active Project').first().json;
const queryParts = [
  chapterPlan.title || '',
  (chapterPlan.plot_goals || []).join(' '),
  (chapterPlan.characters_involved || []).join(' '),
  (chapterPlan.locations_involved || []).join(' '),
  project.genre.join(' '),
  project.tone || ''
].filter(Boolean);
const retrievalQuery = queryParts.join(' ');
return [{
  json: {
    retrieval_query: retrievalQuery,
    project_id: project.id,
    chapter_plan: chapterPlan,
    top_k: 12
  }
}];

const project = $('Load Active Project').first().json;
const chapterPlan = $('Select Next Chapter Plan').first().json;
const projectConfig = $('Load Project Config').all();
const structuredCanon = $('Load Structured Canon').all();
const vectorContext = $('Retrieve Vector Context').all();
const job = $('Acquire Lock').first().json;
let styleGuide = {};
let hardRules = [];
let softRules = [];
let recentSummaries = [];
let systemSettings = {};
for (const item of projectConfig) {
  const j = item.json;
  if (Array.isArray(j)) {
  }
  if (j.narrative_perspective) styleGuide = j;
  if (j.rule_type === 'hard') hardRules.push(j);
  if (j.rule_type === 'soft') softRules.push(j);
  if (j.summary && j.sequence) recentSummaries.push(j);
  if (j.key && j.value) systemSettings[j.key] = j.value;
}
let characters = [];
let characterStates = [];
let locations = [];
let plotThreads = [];
let foreshadowing = [];
let timelineEvents = [];
for (const item of structuredCanon) {
  const j = item.json;
  if (j.role) characters.push(j);
  if (j.physical_state || j.emotional_state) characterStates.push(j);
  if (j.location_type) locations.push(j);
  if (j.thread_type) plotThreads.push(j);
  if (j.clue_text) foreshadowing.push(j);
  if (j.event_time_label) timelineEvents.push(j);
}
const writingBrief = {
  project: {
    id: project.id,
    title: project.name,
    genre: project.genre,
    tone: project.tone,
    style_profile: project.style_profile
  },
  chapter_plan: {
    id: chapterPlan.id,
    sequence: chapterPlan.sequence,
    title: chapterPlan.title,
    plot_goals: chapterPlan.plot_goals || [],
    summary: chapterPlan.summary || '',
    arc_stage: chapterPlan.arc_stage || '',
    major_events: chapterPlan.major_events || []
  },
  target_word_count: chapterPlan.target_word_count || project.daily_target_words || 3000,
  recent_summaries: recentSummaries.reverse(),
  active_characters: characters,
  character_states: characterStates,
  locations: locations,
  plot_threads: plotThreads,
  foreshadowing: foreshadowing,
  timeline_events: timelineEvents,
  canon_rules: { hard: hardRules, soft: softRules },
  style_guide: styleGuide,
  retrieved_context: vectorContext.map(v => ({
    id: v.json.id,
    source_type: v.json.source_type,
    title: v.json.title,
    content: v.json.content,
    similarity: v.json.similarity
  })),
  hard_constraints: hardRules.map(r => r.rule_text),
  quality_threshold: project.quality_threshold || 85,
  max_revise_count: project.max_revise_count || 2,
  auto_publish: project.auto_publish || false
};
return [{
  json: {
    job_id: job.id,
    project_id: project.id,
    chapter_plan_id: chapterPlan.id,
    writing_brief: writingBrief,
    auto_publish: project.auto_publish || false,
    quality_threshold: project.quality_threshold || 85,
    max_revise_count: project.max_revise_count || 2
  }
}];

const writerResult = $input.first().json;
return [{
  json: {
    error: writerResult.error || 'Unknown writer error',
    stderr: writerResult.stderr || '',
    exitCode: writerResult.exitCode || -1,
    duration_ms: writerResult.duration_ms || 0
  }
}];

